def cache(seconds):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            key = f"{func.__name__}_{args}_{kwargs}"
            cached_result = redis_client.get(key)
            if cached_result:
                return cached_result.decode('utf-8')
            result = func(*args, **kwargs)
            redis_client.setex(key, seconds, result)
            return result
        return wrapper
    return decorator

